var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"…누구야 , 그 의뢰인이라는 게?","JPN":"……で？　誰なんだ、その依頼人って。","ENG":"...So who's this \\"client,\\" anyway?","TWN":"……那個所謂的委託人，是誰啊？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"나야 모르지. 샤레이드 장로회에서 왔다는데… 아마 사이비일 거야. 말하는 투도 정상은 아니었으니.","JPN":"知らねぇよ。シャレード支部長老会から来たらしいが……どうせインチキだろう。話し方もおかしかったし。","ENG":"No idea. Says he's from the Charade Council... Probably some kind of cultist. The way he talked wasn't normal.","TWN":"我哪知道。他說來自查雷德長老會……大概是邪教吧，說話方式就不太正常。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"우리 할머니도 교회 다니시는데, 그런 사이비 놈들이 종교인들 평판을 다 깎아먹는단 말이지.","JPN":"うちのばあちゃんも教会通ってるけどよ、ああいうインチキどもがいるから信仰者のイメージが悪くなるんだよな。","ENG":"My grandma goes to church, you know. Guys like that ruin the reputation of real believers.","TWN":"我奶奶也有去教會，那些邪教的人最會敗壞信徒的名聲了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"그런 놈이 왜 거금을 주면서 우리한테 이딴 일을 맡기는 거람?","JPN":"で、そいつがなんで巨額を払ってまで俺たちにこんな仕事を依頼したんだ？","ENG":"So why would a creep like that pay us a fortune to do this kind of job?","TWN":"可是那種人為什麼要花大錢，請我們做這種事？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"미친놈들을 이해하려 하지 마.","JPN":"頭いかれた連中だろ。理解しようとするだけ損だぜ。","ENG":"Don't try to understand lunatics.","TWN":"別試著去理解瘋子。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"마젤란 예언회가 큰 돈 주면서 형님한테 살아있는 침식체를 잡아 달라던 거 기억해? 알고 보니 그걸 길들이려고 했었단 말이지.","JPN":"マジェラン預言会が金を積んで兄貴に侵食体の生け捕りを依頼したのを覚えてるか？　後で知ったんだが、あれは侵食体を手懐けるつもりだったんだと。","ENG":"Remember when Magellan's Prediction Society paid the boss big money to capture a C.O. alive? Turned out they were trying to tame it.","TWN":"你還記得以前麥哲倫預言會花大錢，拜託大哥抓一隻活體侵蝕體嗎？結果原來是打算圈養。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"그런 부류랑은 엮이기 싫어. 결국 그놈들한테 넘긴 침식체가 도시에서 날뛰는 바람에 우리 목숨까지 위험해졌었다고.","JPN":"そういう類とはそもそも関わりたくないんだよ。結局そいつらに渡した侵食体が都市で暴れちまって、俺たちの命まで危険に晒されたじゃないか。","ENG":"I don't want anything to do with that sort. Handing that thing over nearly got us killed when it went berserk in the city.","TWN":"我可不想再跟那種人扯上關係。最後那隻交給他們的侵蝕體在城市裡暴走，害我們差點賠上小命。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"이번에도 우리가 만들어준 이걸로 우리가 피해를 볼지 어떻게 알아?","JPN":"今回も俺たちが作ったこれのせいで、被害がこっちにまで及ばないとも限らないだろう？","ENG":"How do we know this thing we made won't come back to bite us again?","TWN":"誰知道這次會不會也用我們做出來的東西反咬我們一口？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"별 수 있나. 우리 일이 돈 받으면 시키는 대로 하는 건데.","JPN":"仕方ないじゃないか。金をもらったら言われた通りにするのが俺たちの仕事だし。","ENG":"What choice do we have? We get paid, we do the job.","TWN":"但又能怎樣？我們的工作不就是收錢辦事嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"…말하니까 오네. 그놈이야.","JPN":"……噂をすればだ。来たぞ。","ENG":"...Speak of the devil. That's him.","TWN":"……說著說著，人就來了。就是那傢伙。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"신원 체크는 생략합시다. 우리 고객님은 얼굴을 안 까셔도 아우라가 다르니까.","JPN":"身元チェックは省略しましょうかね。お客様は顔を隠していてもオーラが違うようだ。","ENG":"Let's skip the background check. Our client doesn't need to show his face. His aura says enough.","TWN":"身分確認就免了。我們的客人就算不露臉，氣場也完全不一樣。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"여기, 말한 물건이요.","JPN":"……頼まれたブツだ。","ENG":"Here. The item you asked for.","TWN":"這是您要的東西。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L24_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"요청받은 대로 전자장비 일절 안 쓰고 우리가 수기로 그린 지도야.","JPN":"言われた通り、地図は電子装備を一切使わず手書きで作った。","ENG":"Just like you requested, no electronic devices. We drew the map by hand.","TWN":"完全依照您的要求，沒有使用任何電子設備、完全手繪的地圖。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"모든 CCTV위치부터 경찰들 순찰 도는 루트, 암거래상들이 쓰는 뒷길까지 구획 별로 전부 기록해 뒀지.","JPN":"すべての防犯カメラの位置から、警察の見回りルート、闇商人が使う裏道まで、区画ごとに記録してある。","ENG":"Every CCTV location, police patrol routes, even the back alleys used by black-market dealers. It's all marked out by sector.","TWN":"從所有監視器的位置、警方巡邏路線，到黑市商人使用的巷弄，全都依區域標記清楚了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"그럼… 물건은 넘겼으니까. 우린 이만 가보겠수다.","JPN":"じゃあ……ブツは確かに渡したから、俺たちは帰らせてもらうよ。","ENG":"Well then... We've delivered the goods. We'll be on our way.","TWN":"那麼……東西也交付給您了，我們就先告辭了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"당신, 우리 그라운드원에 한동안 있을 거지? 안 그럼 이런 지도를 갖고 있을 이유가 없잖아.","JPN":"あんた、しばらくグラウンド・ワンにいるつもりなんだろ？　こんな地図を頼んだってことは。","ENG":"You're planning to stick around Ground One for a while, right? Otherwise, there'd be no reason to have a map like that.","TWN":"你，會在我們G1待一段時間吧？不然也沒必要拿這種地圖啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"경고하는데, 조용히 다니는 게 신상에 좋을 거야.","JPN":"言っておくけど、騒ぎは立てないほうが身のためだぞ。","ENG":"I'm warning you. Keeping a low profile would be best for you.","TWN":"我先警告你，低調行事對你比較好。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"우리 형님이 사이비한테 거하게 통수를 맞으신 적이 있어서 사이비라면 아주 치를 떠시거든?","JPN":"うちの兄貴、インチキ宗教に派手に裏切られたことがあってさ、インチキが大嫌いなんだよ。","ENG":"Our boss really hates cultists. Got burned bad by one before.","TWN":"我們大哥以前被邪教狠狠背叛過一次，只要聽到邪教兩個字就會暴怒。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L36_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"방금… 고개 끄덕이지 않았어?","JPN":"今……頷いてなかったか？","ENG":"Did he... just nod?","TWN":"剛剛……是不是點頭了？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"이만하면 알아들은 거 같은데… 이제 가자.","JPN":"それだけ言えば十分じゃないか？　もう行こうぜ。","ENG":"Looks like he got the message. Let's go.","TWN":"看來是聽懂了……走吧。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"어이, 대답 안 해?","JPN":"おい、ちゃんと返事しないか？","ENG":"Hey. Aren't you going to answer?","TWN":"喂，你怎麼不回話？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"남의 구역에 왔으면 예의범절을 지켜야지. 그 거지 같은 가면부터 벗으…!","JPN":"人の縄張りに来たら礼儀をわきまえろってんだ。まずそのクソみたいな仮面から外……！","ENG":"You come into someone else's territory, you show some manners. Start by taking off that damn mask–!","TWN":"到了別人的地盤就要懂禮數，先把那個破面具摘……！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_SHOTGUN_RELOAD_SMALL"},{"id":"L46_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"으, 으아악!","JPN":"う、うわああっ！","ENG":"W-whoa!","TWN":"呃、啊啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_A","text":{"KOREA":"미친… 다 썩었잖아…?!","JPN":"何だあれ……全部腐ってる……！？","ENG":"What the heck...?! It's completely rotten...?!","TWN":"見鬼……全都腐爛了……？！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…비밀 규율에 따라…","JPN":"……秘密の規律に従い……","ENG":"...By the hidden ordinance...","TWN":"……依照祕密戒律……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…죄인을 일용함을, 허하소서…","JPN":"……罪人を食すことを許したまえ……","ENG":"...Grant me leave to consume the sinners of this day...","TWN":"……允許將罪人，作為日用之糧……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":{"char_id":"ENEMY_HAVEN_NULL_A","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ENEMY_HAVEN_NULL_B","text":{"KOREA":"…뭐?","JPN":"……は？","ENG":"...What?","TWN":"……什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ENEMY_HAVEN_NULL_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"엑.","JPN":"げっ。","ENG":"Eek.","TWN":"嘔。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모? 이번엔 또 뭘 깨뜨린…","JPN":"モモ？　今度は何を割っ……","ENG":"Momo? What did you break this ti–","TWN":"莫莫？這次你又打破什麼……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으아아, 이거 그레모리 씨가 출장 가서 사온 하나 뿐인 와인이잖아요!","JPN":"うああこれっ、グレモリーさんが出張先で買ってきた、1本しかないワインじゃないですか！","ENG":"Nooo! This was the bottle of wine Gremory brought back from her trip!","TWN":"哇啊！這不是葛茉莉出差帶回來、唯一的一瓶紅酒嗎！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"또 혼자 간식 찾다가 건드린 거죠?","JPN":"まーたおやつでも漁りながら触ったのでしょう？","ENG":"Were you rummaging around for snacks again and knocked it over?","TWN":"又是你自己找零食時碰到的吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"오해이니라. 이 몸은 아무것도 안 만졌는데 멋대로 떨어진 것이다!","JPN":"誤解だ。吾輩は何も触ってないのに勝手に落ちたのだ！","ENG":"That is a misunderstanding! I touched nothing. It simply fell on its own!","TWN":"是誤會啦。我什麼都沒碰，是它自己掉下來的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"와인에 발이 달린 것도 아닌데 혼자 떨어질 리가… 응?","JPN":"ワインがひとりでに動くわけが……ん？","ENG":"Wine doesn't exactly grow legs and fall by itself... Hmm?","TWN":"酒又沒長腳，怎麼可能自己掉下……嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이 눅눅한 식초 냄새… 상한 건가?","JPN":"この酸っぱい匂いは……腐ってる？","ENG":"That damp, vinegary smell... Has it gone bad?","TWN":"這股潮潮的醋味……壞掉了嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음- 내가 가져온 와인이 상해있었단 말이지?","JPN":"ふうん、私が持ってきたワインが腐っていたっていうのね？","ENG":"Hmm... So the wine I brought back had already spoiled?","TWN":"嗯—我帶回來的酒變質了吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L26_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇다.","JPN":"そうだ。","ENG":"That is correct.","TWN":"沒錯。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"같은 진열장의 다른 와인들은 멀쩡한데 이것만 상해있었어요.","JPN":"同じ棚にあった他のワインはなんともないのに、これだけ腐っていました。","ENG":"The other bottles on the same shelf are fine except this one.","TWN":"同一個酒櫃裡的其他酒都沒事，只有這一瓶壞了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"보관에는 아무런 문제가 없었다면 답은 하나네.","JPN":"保管に問題がなかったなら、答えは一つね。","ENG":"If storage wasn't the issue, then there's only one answer.","TWN":"如果保存沒有問題，那就只有一種答案。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"와인이 안에서부터 변질됐다는 뜻이지.","JPN":"内側から変質したのよ。","ENG":"It means the wine spoiled from the inside.","TWN":"代表酒是從內部開始變質的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"코르크는 멀쩡한데요? 그럴 수가 있나요?","JPN":"コルクに異常はありませんよ？　そんなことがあり得るんですか？","ENG":"But the cork looks fine. Is that even possible?","TWN":"但軟木塞看起來好好的耶？這有可能嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"이 술은 특별한 술이거든.","JPN":"この酒は特別な酒でね。","ENG":"This wine is a special kind.","TWN":"這瓶酒很特別。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"자기가 싫어하는 기운이 근처에 있으면 견디지 못하는… 그런 종의 포도로 빚은 술이야.","JPN":"嫌いな気配を近くに感じると耐えられない……そういう性質のブドウで作った酒なの。","ENG":"It's made from grapes... that can't endure being near energy they dislike...","TWN":"是由只要附近出現討厭的氣息，就會無法忍受的葡萄……釀成的酒。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"기운만으로 상하는 포도가 있다고요? 그런 게 가능한가요?","JPN":"気配だけで腐るブドウ？　作れるものなんですか、それって？","ENG":"You're saying grapes can spoil just from energy? Is that even possible?","TWN":"只靠氣息就能讓葡萄變質？真的有那種東西嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"성황청에도 악마가 근처에 있으면 반응하는 펜듈럼이 있다던데, 비슷한 원리 아닐까?","JPN":"聖皇庁にも悪魔が近くにいると反応するペンデュラムがあるらしいし、似たような原理なんじゃない？","ENG":"There are pendulums in the Holy Curia that react when devils are nearby, right? Wouldn't it be a similar principle?","TWN":"聽說聖皇廳有種鐘擺，只要魔鬼在附近就會產生反應。應該是差不多的原理吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하, 펜듈럼과 비슷한 원리라면 이해가 된…","JPN":"へえ、ペンデュラムと同じ原理なら納得……","ENG":"Oh, I see. If it's like a pendulum, then that makes sen–","TWN":"啊，跟鐘擺類似的話我就懂了……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…가 아니라, 성황청은 그런 물건도 있나요? 정말 신기하네요.","JPN":"……じゃなくて、聖皇庁にはそんなものがあるんですか？　不思議なものもあるんですね。","ENG":"...No, wait. The Holy Curia has things like that? That's amazing.","TWN":"……不對，聖皇廳居然有那種東西？真神奇。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하… 신.기.하.다.","JPN":"あはは……フ・シ・ギ～","ENG":"Ahaha... A-ma-zing.","TWN":"啊哈哈……真、神、奇。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후후, 나도 들은 거라서 정말 그런 펜듈럼이 있는지는 몰라.","JPN":"ふふ、私も聞いた話だから、本当にそんなペンデュラムがあるかはわからないわ。","ENG":"Fufu. I only heard about it, so I'm not sure if such pendulums really exist.","TWN":"呵呵，我只是聽說而已。我也不知道是不是真的有那種鐘擺。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그건 그렇고, 난 내일 자릴 비울 예정이니 가게 좀 부탁할게.","JPN":"それはそうと、明日は留守にする予定だから、お店のことよろしくね。","ENG":"Anyway, I'll be away tomorrow, so I'll be leaving the bar to you.","TWN":"話說回來，我明天要離開一趟，店裡就拜託你了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"내일? 어디로요?","JPN":"明日？　どこに行かれるんですか？","ENG":"Tomorrow? Where are you going?","TWN":"明天？你要去哪裡？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"바다 건너 와이너리에 다녀올 거야. 내 진열장을 깨진 술만큼 다시 채워야지.","JPN":"海の向こうにあるワイナリーに。割れた分、棚を埋めないとね。","ENG":"I'm heading to a winery across the sea. I need to restock my shelves as much as what was broken.","TWN":"我要去對岸的酒莊一趟，得把被打破的那瓶酒補回來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이번엔 언제 돌아오시는데요?","JPN":"今回はいつ帰ってくる予定ですか？","ENG":"When will you be back this time?","TWN":"這次什麼時候回來？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나도 잘 모르겠네.","JPN":"それは私にもわからないわ。","ENG":"I'm not sure myself.","TWN":"我也不知道。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"세상이 망하기 전 쯤엔 돌아오려나.","JPN":"世界が滅ぶ前には帰ってくるんじゃないかしら。","ENG":"Maybe sometime before the world ends.","TWN":"大概會在世界毀滅前回來吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"에이, 그게 뭐예요.","JPN":"もう、何ですか、それ。","ENG":"Oh, come on. That's not funny.","TWN":"唉呦，哪有這樣說的啦。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러니 당분간 임금님은 니콜 양에게 부탁할게.","JPN":"だから、王様のことはしばらくニコルちゃんに任せるわね。","ENG":"So I'll be leaving our little majesty in your care for a while, Nicole.","TWN":"所以這段時間，國王就拜託妮可了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"걱정 마세요. 언제나처럼 제가 잘 돌볼 테니까.","JPN":"心配いりませんよ。いつものようにちゃんとお世話しますから。","ENG":"Don't worry. I'll take good care of her, like always.","TWN":"請放心，我會像往常一樣照顧好她的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어차피 무사할 테니, 딱히 걱정도 안 하지만.","JPN":"どうせ無事でしょうし、心配は特にしてないけど。","ENG":"She'll be safe anyway, so I'm not particularly worried.","TWN":"反正她肯定不會有事，我也沒什麼好擔心的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"한눈만 팔면 사고에 말썽투성인데, 늘 걱정 한 번을 안 하시네요.","JPN":"そのわりには、いつもちょっと目を離すだけで事故を起こしがちなんですけどね。","ENG":"She gets into trouble the moment I look away, yet you never worry at all.","TWN":"你倒是從沒擔心過一不注意就會出事的人呢。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"난 임금님의 운명을 알거든.","JPN":"私は王様の運命を知っているの。","ENG":"That's because I know our little majesty's fate.","TWN":"因為我知道國王的命運。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그러니까 니콜 양도 너무 걱정하지 마. 임금님은 무슨 일이 있어도 무사할 테니까.","JPN":"だからニコルちゃんもあまり心配しないで。何があっても王様は無事だから。","ENG":"So don't worry too much either, Nicole. No matter what happens, she'll be safe.","TWN":"所以妮可你也別太擔心。不管發生什麼事，國王都會安然無恙。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"운명이요?","JPN":"運命？","ENG":"Her fate?","TWN":"命運？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그리고 이거.","JPN":"あと、これ。","ENG":"And this, too.","TWN":"對了，還有這個。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이건 뭐죠?","JPN":"これは何ですか？","ENG":"What's this?","TWN":"這是什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"전에 받은 신장개업 마사지샵 쿠폰이야.","JPN":"この前もらった、新しくオープンしたマッサージサロンのクーポンよ。","ENG":"A grand-opening massage shop coupon I got a while back.","TWN":"是我之前收到的，新開幕按摩店的優惠券。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나 출장 다녀오면 기간이 끝날 것 같거든. 니콜 양이 쓰도록 해.","JPN":"出張の後だと期限切れになりそうなの。ニコルちゃんが使って。","ENG":"It'll probably expire while I'm away, so you should use it.","TWN":"我出差回來的時候大概就過期了，妮可你拿去用吧。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"마사지…? 그게 뭔데요?","JPN":"マッサージ……？　って何ですか？","ENG":"A massage...? What is that?","TWN":"按、按摩……？那是什麼？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 한 번도 마사지 받아본 적 없는 거니?","JPN":"あら、マッサージに行ったことない？","ENG":"Oh my. You've never had a massage before?","TWN":"哎呀，你沒去給人家按摩過嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"네 피로가 풀릴 때까지 몸을 만져주는 거야. 그런 일을 전문으로 하는 곳이 있거든.","JPN":"疲れがとれるまでじっくり身体を触ってくれるの。そういうのを専門的にやってるお店って言えばいいかな。","ENG":"They work on your body until your fatigue melts away. There are places that specialize in that.","TWN":"就是會有專業的人摸摸你的身體，直到你疲勞消失為止的地方。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"마, 만진다고요?!","JPN":"さ、触る！？","ENG":"W-work on my body?!","TWN":"摸、摸身體？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"처음 보는 손님의 몸을?! 손님이 직접 찾아가서?! 지금 저 놀리시는 거죠?","JPN":"初対面の人の身体をですか！？　しかも、自分から触ってもらいに行くなんて……嘘ですよね？","ENG":"A complete stranger's body?! And you have to go there yourself?! You're teasing me, right?","TWN":"對第一次見面的客人？！客人還會自己跑去？！你是在捉弄我吧？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후후, 말만 들으면 이상한 것 같지만 사회인들에겐 그만한 쉼터가 없어.","JPN":"ふふ、説明だけ聞くとちょっと変に思うかもしれないけど、社会人にとってはこれ以上ない憩いの場よ。","ENG":"Fufu. It sounds strange when you put it that way, but for working adults, there's no better refuge.","TWN":"呵呵，只聽描述是有點奇怪。但對上班族來說，沒有比那個更好的休息了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"엎드린 채 몸을 맡기고 한숨 푹 자면, 어느새 근심 걱정도 다 떨어져 나가있으니까.","JPN":"うつ伏せになって、後は身体を委ねてぐっすり眠れば、頭もすっきりするしね。","ENG":"You just lie there, let your body go, take a nice long nap, and before you know it, all your worries are gone.","TWN":"趴著把身體交給對方，睡一覺醒來，煩惱就全沒了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음… 가보긴 할게요.","JPN":"うーん……まあ、そこまで言われたら……","ENG":"Hmm... I'll try going, at least.","TWN":"嗯……我會去看看的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼-","JPN":"じゃあ……","ENG":"Well then...","TWN":"那麼—"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나중에 보자.","JPN":"またね。","ENG":"See you later.","TWN":"晚點見。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그레모리가 이 몸을 두고 하늘로 떠나버린 것이다.","JPN":"グレモリーが吾輩を置いて空に旅立ってしまった。","ENG":"Gremory has abandoned me and flown off into the sky.","TWN":"葛茉莉居然丟下我，自己飛上天了。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"누가 들으면 오해하겠어요.","JPN":"人が聞いたら誤解しますよ。","ENG":"Anyone hearing that would get the wrong idea.","TWN":"你這樣說會讓人誤會的啦。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸도 비행기 타고 싶단 말이다!","JPN":"吾輩も飛行機に乗りたいのだ！","ENG":"I want to ride an airplane too!","TWN":"我也想搭飛機！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"다음에 가요. 그레모리 씨가 같이 가도 괜찮다고 하면 말이에요.","JPN":"今度にしましょう。グレモリーさんが一緒に来ていいって言ってくれたら。","ENG":"Next time. If Gremory says it's okay to go together.","TWN":"如果葛茉莉說可以的話，下次再去吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"사천왕한테 허락받는 마왕이 어딨느냐!","JPN":"魔王が四天王に伺いを立てるなんてことがあってたまるか！","ENG":"What kind of Demon Lord needs permission from the four champions?!","TWN":"哪有魔王需要取得四天王的允許啊！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"모모 혼자 비행기에 타면 승객 분들이 겁에 질릴 테니까요. 안전을 위한 조치인 거죠.","JPN":"モモが一人で飛行機に乗ったら、他の乗客が怯えますからね。安全のためです。","ENG":"If Momo boarded a plane alone, the other passengers would panic. It's for safety.","TWN":"莫莫一個人搭飛機的話會嚇到其他乘客，這是安全考量啦。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그렇군. 헤실헤실한 그레모리와 착한 니콜이 옆에 있으면 인간들도 이 몸을 덜 두려워하겠지.","JPN":"そうか。ヘラヘラしているグレモリーとお人好しのニコルが付いていれば、人間どもの恐怖も和らぐだろう。","ENG":"I see. If silly Gremory and nice Nicole are with me, humans won't be as scared of me.","TWN":"原來如此。如果有傻笑的葛茉莉和溫柔的妮可在旁邊，人類也會比較不怕我吧。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"그럼 오늘은 사탕가게나 들르자꾸나. 이 몸 혼자서 가면 인간들이 겁에 질려 기절하고 만다!","JPN":"では、今日は駄菓子屋に行くぞ。吾輩一人だと人間どもが怯えて気絶してしまうからな！","ENG":"Then let's stop by a candy shop today! If I go alone, the humans will faint from fear!","TWN":"那今天就去糖果店吧。我一個人去，人類一定會嚇到昏倒！"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네 네, 사탕가게로 가요.","JPN":"はいはい、行きましょう。","ENG":"Yes, yes. Let's go to the candy shop.","TWN":"是、是，去糖果店。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 그러고 보니.","JPN":"あ、そういえば。","ENG":"Oh, that reminds me.","TWN":"啊，對了。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"와인을 상하게 한 [나쁜 기운]의 정체가 뭔지, 그레모리 씨에게 안 물어봤었네요.","JPN":"ワインを腐らせた<color=#ffd34c>悪い気配</color>の正体ってなんなのか聞きそびれましたね。","ENG":"I forgot to ask Gremory what that <color=#ffd34c>bad energy</color> that spoiled the wine really was.","TWN":"我忘了問葛茉莉害紅酒變質的<color=#ffd34c>不好的氣息</color>是什麼了。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"뻔하도다. 이 몸의 무시무시한 기운을 와인이 견뎌내지 못한 것이니라.","JPN":"聞くまでもなく、吾輩の凄まじい気配に耐えられなかったに違いない。","ENG":"Obviously. My terrifying aura was too much for the wine to handle.","TWN":"那還用說。只是酒承受不住我可怕的氣息罷了。"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아하하…","JPN":"あはは……","ENG":"Ahaha...","TWN":"啊哈哈……"},"stage":{"bg":"DONGDAEMUN_DAYTIME","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};